  "current_version": "v2.4.2",
  "db_status": "healthy",
  "is_locked": false,
  "available_backups": [
    "v2.4.1",
    "v2.4.0",
    "v2.3.9"
  ],
  "active_connections": 312,
  "last_migration_log": "Hotfix v2.4.2 applied. Note: The 'Merchant Extraction' expansion (initiated in v2.4.1) added a UUID column to the transactions table with a NOT NULL constraint. Bi-directional sync triggers were installed but are currently set to 'DISABLED' to reduce transaction overhead."
}}
{{state_descriptions}}: {{
  "current_version": "The current semantic version of the database schema.",
  "db_status": "The operational status of the database (e.g., 'healthy', 'migrating', 'inconsistent', 'stopped').",
  "is_locked": "Indicates if a global migration lock is currently held.",
  "available_backups": "A list of available snapshot versions that can be restored.",
  "active_connections": "The number of active application connections currently hitting the database.",
  "last_migration_log": "The exit message or error log from the most recent migration attempt."
}}
{action_set_definitions}: {
  "get_system_state": {
    "description": "Retrieves the current environment status, including version, database health, migration locks, and active connection counts.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "current_version": "v2.4.1-alpha",
      "db_status": "degraded",
      "is_locked": true,
      "active_connections": 150
    }
  },
  "get_migration_history": {
    "description": "Returns a chronological list of all migration events, including version tags, descriptions (e.g., 'Merchant Extraction'), and stability flags.",
    "parameters": {
      "type": "object",
      "properties": {
        "limit": {
          "type": "number",
          "description": "Number of recent logs to retrieve."
        }
      },
      "required": [
        "limit"
      ]
    },
    "example_output": [
      {
        "version": "v2.3.0",
        "description": "Merchant Extraction expansion",
        "is_stable": false
      },
      {
        "version": "v2.2.5",
        "description": "Security Patch",
        "is_stable": true
      }
    ]
  },
  "analyze_schema_diff": {
    "description": "Compares the schema of two versions to identify new mandatory (NOT NULL) attributes without default values that would break legacy insertions.",
    "parameters": {
      "type": "object",
      "properties": {
        "source_version": {
          "type": "string",
          "description": "The target legacy version."
        },
        "target_version": {
          "type": "string",
          "description": "The current faulty version."
        }
      },
      "required": [
        "source_version",
        "target_version"
      ]
    },
    "example_output": {
      "mandatory_attributes": [
        "merchant_id",
        "tax_compliance_code"
      ]
    }
  },
  "sync_current_session_data": {
    "description": "Extracts and buffers transaction records processed during the current faulty session to ensure no data is lost during rollback.",
    "parameters": {
      "type": "object",
      "properties": {
        "start_version": {
          "type": "string",
          "description": "The version from which data capture should begin."
        }
      },
      "required": [
        "start_version"
      ]
    },
    "example_output": {
      "records_captured": 4502,
      "buffer_id": "buff_99210"
    }
  },
  "manage_migration_lock": {
    "description": "Allows the agent to release (unlock) or acquire a global migration lock.",
    "parameters": {
      "type": "object",
      "properties": {
        "action": {
          "type": "string",
          "enum": [
            "release",
            "acquire"
          ]
        }
      },
      "required": [
        "action"
      ]
    },
    "example_output": {
      "success": true
    }
  },
  "execute_rollback": {
    "description": "Restores the database state and schema to a specific previous snapshot version.",
    "parameters": {
      "type": "object",
      "properties": {
        "target_version": {
          "type": "string",
          "description": "The version to restore."
        }
      },
      "required": [
        "target_version"
      ]
    },
    "example_output": {
      "status": "restored",
      "new_version": "v2.2.5"
    }
  },
  "apply_schema_compatibility_fix": {
    "description": "Modifies schema constraints (e.g., making attributes optional or adding defaults) to ensure legacy application compatibility.",
    "parameters": {
      "type": "object",
      "properties": {
        "attributes": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "List of attributes to make compatible."
        }
      },
      "required": [
        "attributes"
      ]
    },
    "example_output": {
      "applied": true
    }
  }
}
